static char sx__str3388[]="usage:";
static char sx__str3389[]="  spectre <command> [args] | <input.sx> [options]";
static char sx__str3390[]="";
static char sx__str3391[]="commands:";
static char sx__str3392[]="  init   <name>        Initialize a new project";
static char sx__str3393[]="  build  <config>      Build using a config from sx.mod";
static char sx__str3394[]="  run    <input.sx>    Compile and immediately run a program";
static char sx__str3395[]="  doc    <path>        Generate docs for a given .sx into ./docs-out/";
static char sx__str3396[]="  add    <git-url>     Clone a git dependency into ./lib/ and record it";
static char sx__str3397[]="  remove <dep-name>    Remove a dependency by repository name";
static char sx__str3398[]="  ref                  Generate the language reference in the current directory";
static char sx__str3399[]="  clean                Remove build artifacts";
static char sx__str3400[]="  doctor               Show system and Spectre installation information";
static char sx__str3401[]="";
static char sx__str3402[]="options:";
static char sx__str3403[]="  --ast                Print the AST in a unicode tree and exit";
static char sx__str3404[]="  --syntax-check       Check validity of syntax given some program";
static char sx__str3405[]="  --emit-ssa           Print QBE IR to stdout and exit";
static char sx__str3406[]="  --emit-alt           Print alternative IR to stdout and exit";
static char sx__str3407[]="  --emit-asm           Print assembly to stdout and exit";
static char sx__str3408[]="  --src-target=<os>    Mock target OS for when-blocks in source output";
static char sx__str3409[]="  --translate-c        Translate C input into a single .sx file";
static char sx__str3410[]="  --inc-path=<dir>     Add a an include search path for the alt backend";
static char sx__str3411[]="  --show-cmd           Show the command used for linking";
static char sx__str3412[]="  --test               Run the unit tests in the current file";
static char sx__str3413[]="  --release            Build in release mode";
static char sx__str3414[]="  --dll                Build a shared library";
static char sx__str3415[]="  -a, --alt            Compile with fallback backend";
static char sx__str3416[]="  -b, --bootstrap      Display backend output on error";
static char sx__str3417[]="  -c, --compile        Compile only to produce object file, without linking";
static char sx__str3418[]="  -o, --output <file>  Output path for binary or build artifact";
static char sx__str3419[]="  -l, --loud           Show stages of compilation with verbose output";
static char sx__str3420[]="  -v, --version        Show the version of the Spectre compiler";
static char sx__str3421[]="  -h, --help           Print this help message";
static char sx__str3422[]="Spectre %s\n(C) Navid Momtahen - GPL-3.0 - 2026";
